import crypto from 'crypto';

// ============================================
// 【請在此處手動輸入您藍新後台看到的正確值】
// ============================================
const HASH_KEY = 'reBIIWJl6s7csh3eAZTzSTxDA1pW6UVh';
const HASH_IV = 'P1ayLDVHQc4HIXvC';

// 【請貼上您上一筆 Log 中出現的 TradeInfo (CF60EA...那一長串)】
const TRADE_INFO_HEX = '';

// ============================================

console.log('--- SHA-256 手動檢測工具 ---');

// 1. MS 帳號特規公式 (不帶 TradeInfo=)
const rawStringMS = `HashKey=${HASH_KEY}&${TRADE_INFO_HEX}&HashIV=${HASH_IV}`;
const shaMS = crypto.createHash('sha256').update(rawStringMS).digest('hex').toUpperCase();

// 2. 標準 2.0 公式 (帶 TradeInfo=)
const rawStringStd = `HashKey=${HASH_KEY}&TradeInfo=${TRADE_INFO_HEX}&HashIV=${HASH_IV}`;
const shaStd = crypto.createHash('sha256').update(rawStringStd).digest('hex').toUpperCase();

console.log('公式1 (MS 無標籤):', rawStringMS.substring(0, 100) + '...');
console.log('=> 結果:', shaMS);
console.log('');
console.log('公式2 (標準 2.0):', rawStringStd.substring(0, 100) + '...');
console.log('=> 結果:', shaStd);
console.log('---------------------------');
